369→    private fun onPostItemClicked(postId: Long, blogId: Long) {
370→        launch {
371→            findPost(postId, blogId)?.let {
372→                readerPostCardActionsHandler.handleOnItemClicked(
373→                    it,
374→                    ReaderTracker.SOURCE_DISCOVER
375→                )
376→            }
377→        }
378→    }
