513→    fun swipeToRefresh() {
514→        readerTracker.track(AnalyticsTracker.Stat.READER_PULL_TO_REFRESH)
515→        swipeToRefreshTriggered = true
516→        launch {
517→            readerDiscoverDataProvider.refreshCards()
518→        }
519→    }
520→
521→    fun onRetryButtonClick() {
522→        launch {
523→            readerDiscoverDataProvider.refreshCards()
524→        }
525→    }
