 28→/**
 29→ * ReaderTagRepository is middleware that encapsulates data related business related data logic
 30→ * Handle communicate with ReaderServices and Actions
 31→ */
 32→class ReaderTagRepository @Inject constructor(
 33→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 34→    @Named(IO_THREAD) private val ioDispatcher: CoroutineDispatcher,
 35→    private val readerUtilsWrapper: ReaderUtilsWrapper,
 36→    private val fetchInterestTagUseCase: FetchInterestTagsUseCase,
 37→    private val followInterestTagsUseCase: FollowInterestTagsUseCase,
 38→    private val fetchFollowedTagUseCase: FetchFollowedTagsUseCase,
 39→    private val getFollowedTagsUseCase: GetFollowedTagsUseCase,
 40→    private val shouldAutoUpdateTagUseCase: ShouldAutoUpdateTagUseCase,
 41→    private val readerTagTableWrapper: ReaderTagTableWrapper
 42→) {
 43→    private val mutableRecommendedInterests = MutableLiveData<ReaderTagList>()
 44→    private val recommendedInterests: LiveData<ReaderTagList> = mutableRecommendedInterests
 45→    private val followingReaderTag = readerUtilsWrapper.getTagFromTagName(ReaderConstants.KEY_FOLLOWING, DEFAULT)
 46→
 47→    suspend fun getInterests(): ReaderRepositoryCommunication {
 48→        return withContext(ioDispatcher) {
 49→            fetchInterestTagUseCase.fetch()
 50→        }
 51→    }
 52→
 53→    suspend fun getUserTags(): ReaderRepositoryCommunication {
 54→        return withContext(ioDispatcher) {
 55→            val userTags = getFollowedTagsUseCase.get()
 56→            if (userTags.isNotEmpty()) {
 57→                SuccessWithData(userTags)
 58→            } else {
 59→                val refresh = shouldAutoUpdateTagUseCase.get(followingReaderTag)
 60→                var result: ReaderRepositoryCommunication = Success
 61→                if (refresh) {
 62→                    result = fetchFollowedTagUseCase.fetch()
 63→                }
 64→                if (result is Success) {
 65→                    SuccessWithData(getFollowedTagsUseCase.get())
 66→                } else {
 67→                    result
 68→                }
 69→            }
 70→        }
 71→    }
 72→
 73→    suspend fun saveInterests(tags: List<ReaderTag>): ReaderRepositoryCommunication {
 74→        return withContext(ioDispatcher) {
 75→            followInterestTagsUseCase.followInterestTags(tags)
 76→        }
 77→    }
 78→
 79→    suspend fun clearTagLastUpdated(tag: ReaderTag) {
 80→        withContext(ioDispatcher) {
 81→            readerTagTableWrapper.clearTagLastUpdated(tag)
 82→        }
 83→    }
 84→
 85→    suspend fun getRecommendedInterests(): LiveData<ReaderTagList> =
 86→        withContext(bgDispatcher) {
 87→            delay(TimeUnit.SECONDS.toMillis(5))
 88→            getMockRecommendedInterests()
 89→        }
 90→
 91→    private suspend fun getMockRecommendedInterests(): LiveData<ReaderTagList> {
 92→        return withContext(ioDispatcher) {
 93→            mutableRecommendedInterests.postValue(getMockInterests())
 94→            recommendedInterests
 95→        }
